import{bQ as a,aL as n,u as t,G as i}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"14｜高可用：InnoDB Cluster","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/14-高可用.md","filePath":"04.MySQL/14-高可用.md","lastUpdated":null}'),e={name:"04.MySQL/14-高可用.md"};function p(l,s,h,r,d,o){return n(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="_14-高可用-innodb-cluster" tabindex="-1">14｜高可用：InnoDB Cluster <a class="header-anchor" href="#_14-高可用-innodb-cluster" aria-label="Permalink to &quot;14｜高可用：InnoDB Cluster&quot;">​</a></h1><p>上一篇搭了主从复制。但主从是手工切换——主库挂了，要人半夜爬起来把从库提成主库、改应用连接。这个过程几分钟到几十分钟，期间服务不可用。</p><p>高可用解决的就是这个——主库挂了，自动切换、应用自动连到新主、服务尽快恢复。本篇讲 MySQL 官方的高可用方案 InnoDB Cluster，以及它底层的手工切换逻辑。</p><p>先分清三个概念：</p><table tabindex="0"><thead><tr><th>能力</th><th>解决什么</th></tr></thead><tbody><tr><td>备份</td><td>误删后回退到过去某时间点</td></tr><tr><td>复制</td><td>数据实时传到多个实例</td></tr><tr><td>高可用</td><td>故障后服务自动恢复</td></tr></tbody></table><p>高可用解决服务可用性，不能修复误删的数据——那要靠备份和 binlog。</p><h2 id="一、主从手工切换-理解切换在做什么" tabindex="-1">一、主从手工切换：理解切换在做什么 <a class="header-anchor" href="#一、主从手工切换-理解切换在做什么" aria-label="Permalink to &quot;一、主从手工切换：理解切换在做什么&quot;">​</a></h2><p>自动切换底层就是手工切换。先理解手工切的过程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 确认主库不可用</span></span>
<span class="line"><span>2. 选延迟最小、数据最全的从库</span></span>
<span class="line"><span>3. 停该从库复制（不再接收旧主变更）</span></span>
<span class="line"><span>4. 关闭只读，宣布它为新主</span></span>
<span class="line"><span>5. 改应用连接入口（指向新主）</span></span>
<span class="line"><span>6. 其他从库改挂新主</span></span>
<span class="line"><span>7. 旧主恢复后以从库身份加入</span></span></code></pre></div><p>核心 SQL：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 新主：停止复制、关只读</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">STOP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> REPLICA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RESET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> REPLICA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ALL;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> GLOBAL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> super_read_only </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> OFF</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 其他从库：改指向新主</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CHANGE REPLICATION SOURCE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TO</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  SOURCE_HOST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;10.0.0.20&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, SOURCE_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3306</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  SOURCE_USER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;repl&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, SOURCE_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;...&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  SOURCE_AUTO_POSITION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">START</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> REPLICA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>第 5 步改应用连接是难点——应用配的是旧主地址，切到新主要改配置、重启或靠 VIP/DNS。这个衔接不好，切换就是&quot;数据库切了但应用还在连旧主&quot;，服务还是不可用。高可用方案要解决的就是让这个衔接自动化。</p><h2 id="二、innodb-cluster-是什么" tabindex="-1">二、InnoDB Cluster 是什么 <a class="header-anchor" href="#二、innodb-cluster-是什么" aria-label="Permalink to &quot;二、InnoDB Cluster 是什么&quot;">​</a></h2><p>InnoDB Cluster 是 MySQL 官方的高可用方案，三个组件：</p><table tabindex="0"><thead><tr><th>组件</th><th>作用</th></tr></thead><tbody><tr><td>Group Replication</td><td>多个 MySQL 组成集群，自动复制、自动故障检测</td></tr><tr><td>MySQL Router</td><td>连接入口，自动把读写路由到正确的节点</td></tr><tr><td>MySQL Shell</td><td>管理工具，建集群、加节点、查状态</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用 → MySQL Router → 主（读写）+ 从（只读）</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     Group Replication 自动同步</span></span></code></pre></div><p>应用连的是 Router，不是直接连 MySQL。Router 知道哪个是主、哪个是从，自动路由——写请求到主、读请求到从。主挂了，Group Replication 自动选新主，Router 自动把流量切过去，应用不用改连接配置。</p><p>这就是它比手工主从强的地方——切换和应用衔接都自动化了。</p><h2 id="三、group-replication-的特点" tabindex="-1">三、Group Replication 的特点 <a class="header-anchor" href="#三、group-replication-的特点" aria-label="Permalink to &quot;三、Group Replication 的特点&quot;">​</a></h2><p>Group Replication（MGR）是 InnoDB Cluster 的底层，多个 MySQL 组成一个组，互相复制：</p><ul><li><strong>自动故障检测</strong>：主挂了，组里其他节点投票检测，自动选新主</li><li><strong>多数派</strong>：集群要过半节点存活才能服务（3 节点挂 1 个还能用，挂 2 个不行）</li><li><strong>强一致</strong>：事务要多数节点确认才算提交（比异步复制更安全，但延迟略高）</li></ul><p>集群节点数推荐奇数（3、5、7）——便于投票多数派。3 节点是最小可用配置，挂 1 个还能服务。</p><h2 id="四、搭建-innodb-cluster-概念流程" tabindex="-1">四、搭建 InnoDB Cluster（概念流程） <a class="header-anchor" href="#四、搭建-innodb-cluster-概念流程" aria-label="Permalink to &quot;四、搭建 InnoDB Cluster（概念流程）&quot;">​</a></h2><p>具体命令细节看官方文档，这里讲流程和理解：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 准备 3 台 MySQL，配好 binlog 和 GTID（和主从复制一样）</span></span>
<span class="line"><span>2. 每台装 Group Replication 插件</span></span>
<span class="line"><span>3. 用 MySQL Shell 建集群：</span></span>
<span class="line"><span>   dba.createCluster(&#39;myCluster&#39;)</span></span>
<span class="line"><span>   cluster.addInstance(&#39;10.0.0.2&#39;)</span></span>
<span class="line"><span>   cluster.addInstance(&#39;10.0.0.3&#39;)</span></span>
<span class="line"><span>4. 部署 MySQL Router，指向集群</span></span>
<span class="line"><span>5. 应用连 Router</span></span></code></pre></div><p><code>dba.createCluster</code> 是 MySQL Shell 提供的命令，封装了 Group Replication 的配置。加节点用 <code>cluster.addInstance</code>——新节点用 Clone 插件从主库同步数据（上一篇讲的 Clone 在这里自动用上），不用手动初始化。</p><p>Router 可以部署多份（和应用一起），避免 Router 自己成单点。</p><h2 id="五、故障切换怎么发生" tabindex="-1">五、故障切换怎么发生 <a class="header-anchor" href="#五、故障切换怎么发生" aria-label="Permalink to &quot;五、故障切换怎么发生&quot;">​</a></h2><p>主库挂了，集群自动处理：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 其他节点发现主不响应（心跳超时）</span></span>
<span class="line"><span>2. 多数节点确认主挂了，触发重新选举</span></span>
<span class="line"><span>3. 选一个数据最新的从当新主</span></span>
<span class="line"><span>4. Router 感知到拓扑变化，把写流量路由到新主</span></span>
<span class="line"><span>5. 应用无感知（连的还是 Router，Router 内部切了）</span></span></code></pre></div><p>整个过程通常几秒到几十秒。期间写请求会失败重试，读请求如果 Router 配了允许走从库则不受影响。</p><p>RTO（恢复时间）和 RPO（数据丢失）：</p><ul><li>RTO：故障到恢复的时间，InnoDB Cluster 几秒到几十秒</li><li>RPO：可能丢失多少数据，强一致模式下基本不丢（多数确认才算提交）</li></ul><h2 id="六、读写分离" tabindex="-1">六、读写分离 <a class="header-anchor" href="#六、读写分离" aria-label="Permalink to &quot;六、读写分离&quot;">​</a></h2><p>Router 可以配读写分离——写走主、读走从：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读写端口（6446）→ 主</span></span>
<span class="line"><span>只读端口（6447）→ 从</span></span></code></pre></div><p>应用按需求连不同端口。一致性要求高的查询（刚写入就要查到）走读写端口（主），报表、统计这类走只读端口（从）。</p><p>注意从库有延迟——刚写入的数据从库可能还没回放，走只读端口查不到。对延迟敏感的走主。</p><h2 id="七、innodb-cluster-的取舍" tabindex="-1">七、InnoDB Cluster 的取舍 <a class="header-anchor" href="#七、innodb-cluster-的取舍" aria-label="Permalink to &quot;七、InnoDB Cluster 的取舍&quot;">​</a></h2><p>不是所有场景都该上 InnoDB Cluster：</p><table tabindex="0"><thead><tr><th>场景</th><th>适不适合</th></tr></thead><tbody><tr><td>单库、能接受分钟级停机</td><td>手工主从够了，别上集群</td></tr><tr><td>需要高可用、有专人维护</td><td>InnoDB Cluster</td></tr><tr><td>超大规模、跨机房</td><td>InnoDB Cluster + ClusterSet 或云托管</td></tr><tr><td>老环境已有 MHA</td><td>可继续用，新环境别再用 MHA（MHA 已老旧）</td></tr></tbody></table><p>InnoDB Cluster 运维复杂度比单机主从高——3 个节点要维护、Router 要部署、集群状态要监控。小项目或能接受短停机的，手工主从更简单。核心业务、不能停的，才值得上集群。</p><h2 id="八、故障演练" tabindex="-1">八、故障演练 <a class="header-anchor" href="#八、故障演练" aria-label="Permalink to &quot;八、故障演练&quot;">​</a></h2><p>上线后要定期演练——模拟主库挂了，看集群切不切得动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在主库上模拟故障</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysqld</span></span></code></pre></div><p>观察：集群是否检测到、是否选了新主、Router 是否把流量切过去、应用是否自动恢复。演练能发现配置问题（比如 Router 没感知到、应用连接超时太短），别等真故障才发现。</p><h2 id="高可用之后" tabindex="-1">高可用之后 <a class="header-anchor" href="#高可用之后" aria-label="Permalink to &quot;高可用之后&quot;">​</a></h2><p>数据存好（安装/SQL/索引）、性能调好（InnoDB/调优）、安全管好（账号）、备份做好、复制和高可用搭好。最后讲常见故障排查——把这些综合起来，出问题时怎么定位。</p>`,48)])])}const u=a(e,[["render",p]]);export{k as __pageData,u as default};
